import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { SeedService } from '../../data/seed.service';
import { CatalogPart } from '../../data/models';

interface Decode {
  voltage: string;
  frame: string;
  accessory: string;
}

@Component({
  selector: 'app-catalog',
  standalone: true,
  imports: [CommonModule, RouterLink, FormsModule],
  templateUrl: './catalog.component.html',
  styleUrl: './catalog.component.css',
})
export class CatalogComponent {
  filterText = signal('');
  selectedId = signal<string | null>(null);

  filtered = computed<CatalogPart[]>(() => {
    const q = this.filterText().trim().toLowerCase();
    if (!q) return this.seed.catalog();
    return this.seed.catalog().filter(
      (p) => p.partNumber.toLowerCase().includes(q) || p.family.toLowerCase().includes(q),
    );
  });

  selectedPart = computed<CatalogPart | undefined>(() => {
    const id = this.selectedId();
    return id ? this.seed.catalog().find((p) => p.id === id) : undefined;
  });

  onFilter(value: string): void {
    this.filterText.set(value);
  }

  // Fabricated decode based on the family.
  decode = computed<Decode | undefined>(() => {
    const p = this.selectedPart();
    if (!p) return undefined;
    switch (p.family) {
      case 'Tmax XT': return { voltage: '600V AC', frame: 'XT6 moulded case, 800A frame', accessory: 'Side-mount aux, 42X spacing' };
      case 'Emax 2': return { voltage: '690V AC', frame: 'E6.2 air frame, 4000A', accessory: 'Ekip Touch trip unit' };
      case 'VD4': return { voltage: '12kV', frame: 'VD4 vacuum, 1250A', accessory: 'Motor charge, shunt trip' };
      case 'ADVAC': return { voltage: '15kV', frame: 'ADVAC vacuum, 2000A', accessory: 'Racking interlock' };
      case 'SafeGear': return { voltage: '15kV', frame: 'Arc-resistant MV cell', accessory: 'UL 891 Annex G, Type 2B' };
      default: return { voltage: '—', frame: 'Standard frame', accessory: 'None specified' };
    }
  });

  // Fabricated 4-point pricing history (bars).
  priceHistory = computed<number[]>(() => {
    const p = this.selectedPart();
    if (!p) return [];
    const base = p.lastQuoted;
    return [Math.round(base * 1.06), Math.round(base * 1.02), Math.round(base * 0.99), base];
  });

  priceHistoryMax = computed(() => Math.max(1, ...this.priceHistory()));

  barPct(v: number): number {
    return Math.round((v / this.priceHistoryMax()) * 100);
  }

  select(id: string): void {
    this.selectedId.set(this.selectedId() === id ? null : id);
  }

  constructor(public seed: SeedService) {}
}
